<?php
 namespace WPAICG\Core\Providers\Traits; if (!defined('ABSPATH')) { exit; } trait ChatCompletionsPayloadTrait { protected function format_chat_completions_payload( string $instructions, array $history, string $user_message, array $ai_params, string $model, bool $include_model = false ): array { $messages = []; if (!empty($instructions)) { $messages[] = ['role' => 'system', 'content' => $instructions]; } foreach ($history as $msg) { $role = ($msg['role'] === 'bot') ? 'assistant' : $msg['role']; $content = isset($msg['content']) ? trim($msg['content']) : ''; if ($content !== '' && in_array($role, ['system', 'user', 'assistant'])) { $messages[] = ['role' => $role, 'content' => $content]; } } if (!empty($user_message)) { $messages[] = ['role' => 'user', 'content' => $user_message]; } $body_data = ['messages' => $messages]; if ($include_model) { $body_data['model'] = $model; } $param_map = [ 'temperature' => 'temperature', 'max_completion_tokens' => 'max_tokens', 'top_p' => 'top_p', 'stop' => 'stop', ]; foreach ($param_map as $aipkit_key => $api_key) { if (isset($ai_params[$aipkit_key])) { $value = $ai_params[$aipkit_key]; if (in_array($api_key, ['temperature', 'top_p'])) { $body_data[$api_key] = floatval($value); } elseif ($api_key === 'max_tokens') { $body_data[$api_key] = absint($value); } elseif ($api_key === 'stop' && !empty($value)) { $body_data[$api_key] = is_string($value) ? [$value] : (is_array($value) ? $value : null); if (empty($body_data[$api_key])) unset($body_data[$api_key]); } } } unset($body_data['max_completion_tokens']); return $body_data; } protected function format_sse_chat_completions_payload( array $messages, string $instructions, array $ai_params, string $model, bool $include_model = false, bool $request_usage = true ): array { $payload = $this->format_chat_completions_payload($instructions, $messages, '', $ai_params, $model, $include_model); if (end($payload['messages'])['role'] === 'user' && empty(end($payload['messages'])['content'])) { array_pop($payload['messages']); } $payload['stream'] = true; if ($request_usage && $this instanceof \WPAICG\Core\Providers\OpenAIProviderStrategy) { } else if ($request_usage && ($this instanceof \WPAICG\Core\Providers\AzureProviderStrategy || $this instanceof \WPAICG\Core\Providers\OpenRouterProviderStrategy)) { $payload['stream_options'] = ['include_usage' => true]; } return $payload; } } 